UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('ae4aed97-aec5-4689-90ae-61277d0ed610'::uuid, 'La toux irrite la gorge, les pastilles miel-propolis aident à adoucir l''inflammation pharyngée et calmer la sensation de picotement.'),('b0c55b9f-8962-4c9f-a748-f95134a96e34'::uuid, 'La toux est souvent due à des voies respiratoires encombrées, l''eucalyptus aide à fluidifier le mucus et faciliter l''expectoration.'),('783f2584-60ae-4399-a576-20825382961f'::uuid, 'Un traitement antiviral peut affaiblir l''immunité, la vitamine D3 aide à renforcer le système de défense pour mieux combattre les infections.'),('3cc0223d-ecb9-49c3-9be4-f0996423e79a'::uuid, 'Le traitement antiviral peut être fatigant, le magnésium aide à réduire la lassitude et à maintenir un bon équilibre nerveux.'),('3f753876-1a7e-460b-ba53-75b53e7c7dbe'::uuid, 'Les antiviraux peuvent perturber la flore intestinale, les probiotiques aident à restaurer l''équilibre du microbiote et l''immunité digestive.'),('4b56495b-e36d-49ef-be46-fad69f471559'::uuid, 'Les traitements contre l''hépatite C peuvent affecter l''immunité, la vitamine D3 aide à soutenir les défenses de l''organisme et la santé osseuse.'),('bf8307d9-8ae6-4988-bc1c-8c77bc2a095c'::uuid, 'Le traitement de l''hépatite C peut entraîner de la fatigue, le magnésium aide à réduire la lassitude et à maintenir un bon équilibre nerveux.'),('b369f129-61e3-4124-a1b2-d7601d2f9044'::uuid, 'Les traitements antiviraux pour l''hépatite C peuvent impacter le microbiote, les probiotiques aident à restaurer l''équilibre digestif et la fonction immunitaire.'),('18c61764-0ad6-4d00-a081-c40732c75ed6'::uuid, 'Le traitement antiviral VIH peut affaiblir l''immunité, la vitamine D3 aide à renforcer le système de défense pour une meilleure protection.'),('81f3abff-4dc5-4d06-bf1b-c9589d6fba22'::uuid, 'Le traitement du VIH peut être fatigant, le magnésium aide à réduire la lassitude et à maintenir l''équilibre neuromusculaire.'),('a84da0fe-b8b5-460e-90b3-b8c5cad9a81d'::uuid, 'Les antiviraux VIH peuvent perturber la flore digestive, les probiotiques aident à restaurer l''équilibre du microbiote intestinal et son rôle immunitaire.'),('ef398a9e-1ca9-44ac-a601-97dd0bb3c6d3'::uuid, 'Les traitements par ARA-II peuvent impacter le système cardiovasculaire, les Oméga 3 aident à réguler la fonction cardiaque.'),('1a32bb03-9dd3-4e10-9c10-da1dbf0e4622'::uuid, 'Les traitements par ARA-II peuvent impacter le système cardiovasculaire, les Oméga 3 aident à réguler la fonction cardiaque.'),('0d5b8a9b-98cf-4b36-b1bc-82a741360a47'::uuid, 'Les traitements par ARA-II peuvent impacter le système cardiovasculaire, les Oméga 3 aident à réguler la fonction cardiaque.'),('04c39ac6-d3c1-415d-90c0-17776ca67bbf'::uuid, 'La thérapie combinée peut augmenter la pression artérielle, les Oméga 3 soutiennent la fonction cardiovasculaire.'),('650da3a7-df6b-4467-ab51-fbd8cbe470e1'::uuid, 'La thérapie combinée peut augmenter la pression artérielle, les Oméga 3 soutiennent la fonction cardiovasculaire.'),('0762be96-aa95-4818-8d10-be7a06a15c81'::uuid, 'La thérapie combinée peut augmenter la pression artérielle, les Oméga 3 soutiennent la fonction cardiovasculaire.'),('5ed3a7ff-6449-4909-9d26-0fada1d7ebdb'::uuid, 'L''insuffisance cardiaque affaiblit le muscle cardiaque, les Oméga 3 favorisent la régulation de l''activité cardiaque.'),('a5674e1a-1a41-495c-b11a-90b222df4b70'::uuid, 'L''insuffisance cardiaque affaiblit le muscle cardiaque, les Oméga 3 favorisent la régulation de l''activité cardiaque.'),('1651398c-444a-4e22-ba3d-f8448a88e7ea'::uuid, 'L''insuffisance cardiaque affaiblit le muscle cardiaque, les Oméga 3 favorisent la régulation de l''activité cardiaque.'),('7f2f1317-4e88-4060-bb98-46f470b3c3f3'::uuid, 'Les traitements AVK peuvent déséquilibrer le système cardiovasculaire, les Oméga 3 aident à maintenir une fonction cardiaque saine.'),('c4fe44cf-c6c1-42e7-8ad2-0498abdb4a4b'::uuid, 'Les traitements AVK peuvent déséquilibrer le système cardiovasculaire, les Oméga 3 aident à maintenir une fonction cardiaque saine.'),('8fd0d6b6-8584-435c-8956-0c8b88c484fe'::uuid, 'Les traitements AVK peuvent déséquilibrer le système cardiovasculaire, les Oméga 3 aident à maintenir une fonction cardiaque saine.'),('db9ab166-632b-4e35-b584-a1c806c22939'::uuid, 'Les bêta-2-agonistes peuvent influencer le système immunitaire, la vitamine D3 renforce les défenses naturelles.'),('27fcc19a-cb51-44b9-b91b-136a296a4b73'::uuid, 'Les traitements peuvent entraîner un épuisement neuromusculaire, le magnésium aide à la relaxation musculaire et nerveuse.'),('8c42a06b-7696-4bd4-9d3c-143e43142f8e'::uuid, 'Certains traitements peuvent perturber la flore intestinale, les probiotiques restaurent l''équilibre de la muqueuse digestive.'),('b16f3f0c-0d29-4768-a304-87bf10ac57b2'::uuid, 'Les bêta-bloquants affectent la régulation cardiovasculaire, les Oméga 3 aident à maintenir une fonction cardiaque normale.'),('9ea95958-cd43-4d73-ac4a-a2f9316f8153'::uuid, 'Les bêta-bloquants affectent la régulation cardiovasculaire, les Oméga 3 aident à maintenir une fonction cardiaque normale.'),('1d13fa24-7be3-4651-bb12-dd9fa5ebe480'::uuid, 'Les bêta-bloquants affectent la régulation cardiovasculaire, les Oméga 3 aident à maintenir une fonction cardiaque normale.'),('a4fec1d8-ddd5-4002-8f89-433bc97fa91f'::uuid, 'Les bêta-bloquants non sélectifs peuvent impacter la fonction cardiaque, les Oméga 3 soutiennent la santé cardiovasculaire.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;